import React, { useState } from 'react';
import { Link } from 'react-router-dom';

export default function Accueil() {
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');

  const handleSubscribe = (e) => {
    e.preventDefault();
    if (!email) {
      setMessage('Veuillez entrer une adresse e-mail valide.');
      return;
    }
    setMessage(`Merci pour votre abonnement, ${email} !`);
    setEmail('');
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Bienvenue sur notre plateforme de réservation</h1>
      <p style={styles.subtitle}>
        Gérez facilement vos salles de réunion, où que vous soyez.
      </p>

      <form onSubmit={handleSubscribe} style={styles.form}>
        <input
          type="email"
          placeholder="Votre e-mail"
          style={styles.input}
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />
        <button type="submit" style={styles.button}>S'abonner</button>
      </form>
      {message && <p style={styles.message}>{message}</p>}

      <div style={styles.links}>
        <Link to="/login" style={styles.linkButton}>Connexion</Link>
        <Link to="/register" style={styles.linkButton}>Inscription</Link>
        <Link to="/reservation" style={styles.linkButton}>Réserver une salle</Link>
      </div>
    </div>
  );
}

const styles = {
  container: {
    maxWidth: 500,
    margin: '50px auto',
    padding: 20,
    textAlign: 'center',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  },
  title: {
    fontSize: 32,
    marginBottom: 12,
    color: '#2c3e50',
  },
  subtitle: {
    fontSize: 18,
    marginBottom: 24,
    color: '#34495e',
  },
  form: {
    display: 'flex',
    justifyContent: 'center',
    marginBottom: 16,
    gap: 8,
  },
  input: {
    flex: 1,
    padding: 12,
    fontSize: 16,
    borderRadius: 6,
    border: '1px solid #bdc3c7',
    outline: 'none',
  },
  button: {
    padding: '12px 24px',
    fontSize: 16,
    backgroundColor: '#2980b9',
    color: 'white',
    border: 'none',
    borderRadius: 6,
    cursor: 'pointer',
    transition: 'background-color 0.3s ease',
  },
  message: {
    color: '#27ae60',
    fontWeight: 'bold',
  },
  links: {
    display: 'flex',
    justifyContent: 'center',
    gap: 15,
    marginTop: 20,
  },
  linkButton: {
    padding: '10px 18px',
    backgroundColor: '#3498db',
    color: 'white',
    borderRadius: 6,
    textDecoration: 'none',
    fontWeight: 'bold',
    transition: 'background-color 0.3s ease',
  },
};
